+export function normalizeErrorStackOptions(
+  value: unknown
+): NormalizedErrorStackOptions | undefined {
+  if (value === null || typeof value !== 'object' || Array.isArray(value)) {
+    return undefined;
+  }
+
+  const input = value as ErrorStackOptions;
+  let mode: ErrorStackMode = modes.has(input.mode as ErrorStackMode)
+    ? (input.mode as ErrorStackMode)
+    : 'off';
+  const maxStackLines = input.maxStackLines;
+  if (
+    maxStackLines !== undefined &&
+    (!Number.isInteger(maxStackLines) || maxStackLines <= 0)
+  ) {
+    mode = 'off';
+  }
