+import { NormalizedErrorStackOptions } from './error-options.js';
+
+type StackOptions = Pick<
+  NormalizedErrorStackOptions,
+  | 'normalizeNewlines'
+  | 'trimLeadingWhitespace'
+  | 'maxStackLines'
+  | 'stripInternalFrames'
+  | 'redactPaths'
+>;
+
+export const normalizeStackNewlines = (stack: string): string =>
+  stack.replace(/\\r\
?/g, '\
');
+
+const trimLines = (lines: string[], trim: boolean) =>
+  trim ? lines.map((line, index) => (index === 0 ? line : line.replace(/^\\s+/, ''))) : lines;
+
+const stripFrames = (lines: string[], mode: StackOptions['stripInternalFrames']) =>
+  lines.filter((line, index) => {
+    if (index === 0) return true;
+    const node = line.includes('node:internal');
+    const superjson = /src\\/(?:transformer|plainer|index)\\.ts/.test(line);
+    return !(
+      (mode === 'node' && node) ||
+      (mode === 'superjson' && superjson) ||
+      (mode === 'node_and_superjson' && (node || superjson))
+    );
+  });
+
+const redactLine = (line: string, mode: StackOptions['redactPaths']) => {
+  if (mode === 'strip_cwd') {
+    const cwd = process.cwd().replace(/\\\\/g, '/');
+    return line.replace(new RegExp(cwd.replace(/[.*+?^${}()|[\\]\\\\]/g, '\\\\$&'), 'g'), '');
+  }
+  if (mode === 'basename') {
+    return line.replace(/(?:[A-Za-z]:)?(?:[\\\\/][^\\\\/\\s():]+)+/g, path => {
+      const parts = path.split(/[\\\\/]/);
+      return parts[parts.length - 1];
+    });
+  }
+  return line;
+};
+
+const splitStack = (stack: string, options: StackOptions) => {
+  const normalized = options.normalizeNewlines ? normalizeStackNewlines(stack) : stack;
+  return trimLines(normalized.split('\
'), options.trimLeadingWhitespace);
+};
+
+export function processStackString(stack: string, options: StackOptions): string {
+  let lines = splitStack(stack, options);
+  lines = lines.map(line => redactLine(line, options.redactPaths));
+  if (options.maxStackLines !== undefined) lines = lines.slice(0, options.maxStackLines);
+  lines = stripFrames(lines, options.stripInternalFrames);
+  return lines.join('\
');
+}
+
+export function processStackFrames(
+  stack: string,
+  options: StackOptions
+): Array<{ raw: string }> {
+  let lines = splitStack(stack, options);
+  lines = stripFrames(lines, options.stripInternalFrames);
+  lines = lines.map(line => redactLine(line, options.redactPaths));
+  if (options.maxStackLines !== undefined) lines = lines.slice(0, options.maxStackLines);
+  return lines.map(raw => ({ raw }));
+}
