+
+const stack = 'Error: bad\\r\
    at first (/work/a.ts:1:1)\\r    at node:internal/foo:2:2\
    at second (/work/b.ts:3:4)';
+
+describe('error stack options', () => {
+  it('normalizes only object options and disables invalid modes and limits', () => {
+    expect(normalizeErrorStackOptions(null)).toBeUndefined();
+    expect(normalizeErrorStackOptions('frames')).toBeUndefined();
+    expect(normalizeErrorStackOptions({})).toMatchObject({ mode: 'off' });
+    expect(normalizeErrorStackOptions({ mode: 'string', maxStackLines: 0 })).toMatchObject({ mode: 'off' });
+    expect(normalizeErrorStackOptions({ includeCauses: 'deep', maxCauseDepth: 1.5 })).toMatchObject({ includeCauses: 'none' });
+  });
+
+  it('exports stack processing helpers with the documented ordering', () => {
+    const options = normalizeErrorStackOptions({
+      mode: 'string', normalizeNewlines: true, stripInternalFrames: 'node', redactPaths: 'basename', maxStackLines: 3,
+    })!;
+    expect(normalizeStackNewlines('a\\r\
b\\rc')).toBe('a\
b\
c');
+    expect(processStackString(stack, options)).toBe('Error: bad\
at first (a.ts:1:1)');
+    expect(processStackFrames(stack, options)).toEqual([
+      { raw: 'Error: bad' }, { raw: 'at first (a.ts:1:1)' }, { raw: 'at second (b.ts:3:4)' },
+    ]);
+  });
+
+  it('keeps legacy stack behavior when omitted, and never leaks stacks in off mode', () => {
+    const error = new Error('bad');
